var e=[{id:`L2_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`아파...... 너무 아파......`,JPN:`痛い……痛いよ……`,ENG:`It hurts... It hurts so much...`,TWN:`痛……太痛了……`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_AMBIENT_RAIN_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`조용히 있어라, 불신자.`,JPN:`静かにしろ、不信者。`,ENG:`Stay quiet, non-believer.`,TWN:`安靜些，未信者。`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_AMBIENT_RAIN_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`넌 위대한 예언자 마젤란님께 선택 받은 존재다.`,JPN:`お前は偉大なる預言者マジェラン様に選ばれた存在だ。`,ENG:`You were chosen by the great Magellan the Prophet.`,TWN:`妳是被偉大的預言者·麥哲倫所選中的存在。`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_AMBIENT_RAIN_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`영광으로 알도록!`,JPN:`光栄に思え！`,ENG:`Accept your fate with gratitude.`,TWN:`妳要感到光榮！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_AMBIENT_RAIN_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`그, 그런거...... 난 몰라요...... 풀어줘요......`,JPN:`そ、そんなの……私は知りません……解放してください……`,ENG:`W-what are you talking about? I don't understand what you're saying. Please let me go...`,TWN:`那、那種事情……我才不管……放我走吧……`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_AMBIENT_RAIN_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`예상하던 반응이로군. 뭐, 상관없다.`,JPN:`予想どおりの反応だな。まあ、いいだろう。`,ENG:`Well, it doesn't matter.`,TWN:`真是預期中的反應啊，算了，無所謂。`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_AMBIENT_RAIN_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`어차피 예언자님을 직접 뵙고 나면 생각이 바뀔 테니까.`,JPN:`どうせ預言者様に直接お目にかかれば、考えが変わるはずだ。`,ENG:`Just a short audience with the prophet will turn your world upside down.`,TWN:`反正妳親自見到預言者大人後，想法就會改變的。`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_AMBIENT_RAIN_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`뭐야? 거기 무슨 일이냐! 소란 피우지 말라고 했을 텐데?!`,JPN:`うん？　そこ、どうしたんだ！　騒ぐなと言ったはずだろ！？`,ENG:`What is it? What's going on there? Didn't I tell you to be calm and quiet?`,TWN:`什麼？那裡是怎麼回事！我不是說過別吵了嗎？！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ZELOT_MAGELLAN_NULL_BAG`,text:{KOREA:`겨, 경찰과 블랙타이드 놈들입니다!`,JPN:`け、警察とブラックタイドのやつらです！`,ENG:`I-it's the police and the Black Tide!`,TWN:`是、是警察和黑潮那些傢伙！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ZELOT_MAGELLAN_NULL_BAG`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_FOOTSTEP_RUNNING_02`},{id:`L14_1`,type:`dialog`,speaker:`ZELOT_MAGELLAN_NULL_BAG`,text:{KOREA:`꼬리를 밟힌 것 같아요!`,JPN:`尻尾を掴まれたようです！`,ENG:`They've followed us!`,TWN:`我們好像被發現了！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ZELOT_MAGELLAN_NULL_BAG`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ANDRO_EXTRA_NULL_NULL`,text:{KOREA:`뭣이?! 어, 어떻게 여길......!!`,JPN:`何！？　ど、どうしてここを……`,ENG:`What? Why are they here?`,TWN:`什麼？！是、是怎麼找到的……！！`},stage:{bg:`PRISON_NIGHT`,bgm:`CUTSCENE_UPROAR`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANDRO_EXTRA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};